def main():
    with open(OUTPUT) as f:
        data = json.load(f)
    
    existing_ids = {p['id'] for p in data['pairs']}
    added = 0
    
    for item in PROVENANCE_DATA:
        if item['id'] in existing_ids:
            continue
        pair = {
            "id": item['id'],
            "type": "provenance_chain",
            "category": item['cat'],
            "subject": item['subject'],
            "valid_indicators": item['valid'],
            "red_flags": item['red'],
            "verification_steps": item['steps'],
            "sources": ["EDITION Authentication Intelligence Framework"],
            "verified_by": "source_verified",
            "created_at": NOW
        }
        data['pairs'].append(pair)
        existing_ids.add(item['id'])
        added += 1
    
    data['total_pairs'] = len(data['pairs'])
    data['generated_at'] = NOW
    
    with open(OUTPUT, 'w') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    
    print(f"✅ Added {added} provenance_chain pairs. Total: {data['total_pairs']}")

if __name__ == '__main__':
    main()
